codeExamples.code:
let a = 2;
let b = 3;
console.log(a > b);
console.log((a + b) > 1);

let e = 8;
let f = 5;
console.log(e >= f);
console.log(e != f);

let a = 1;       // 單等號：把 1 賦值給 a
let b = 2;
console.log(a == b);  // 雙等號：比較 a 和 b 是否相等

let a = 1;
let b = "1";
console.log(a == b);
console.log(a === b);

let a = 1;
let b = 2;
console.log(a == 1 && b == 2);
console.log(a == 1 && b == 5);

let a = 1;
let b = 2;
console.log(a == 1 || b == 5);
console.log(a == 9 || b == 5);

// AND 串三個條件：年滿 18 而且有工作而且信用正常
let age = 25;
let hasJob = true;
let goodCredit = true;
console.log(age >= 18 && hasJob == true && goodCredit == true);

// OR 串三個條件：未滿 6 歲或 65 歲以上或持有殘障證明
let age = 70;
let hasDisabilityCard = false;
console.log(age < 6 || age >= 65 || hasDisabilityCard == true);

